  ('real-estate-moex-00887', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '區段徵收之土地，領回抵價地後第一次移轉，應課徵土地增值稅時，原地價應如何認定？ 以原土地所有權人完成移轉登記之日當期公告土地現值 以原土地所有權人權利取得之日當期公告土地現值 以原土地所有權人實際領回抵價地之地價 以原土地所有權人領得之補償地價總額', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
